const repos = $input.first().json.repos ?? [];
const since = new Date(Date.now() - 150000).toISOString();
return repos
  .filter(r => r.platform === 'github' && r.remote_id && r.remote_id.includes('/'))
  .map(r => {
    const [owner, repo] = r.remote_id.split('/');
    return { json: { owner, repo, name: r.name, since } };
  });

// Separate raw GitHub items into issues and comments, then cross-filter:
// if an issue was updated only because a comment was posted (no real issue
// body/state change), skip the redundant issue_updated event — the comment
// event already captures the activity.

const items = $input.all();

// 1. Classify items: comments have 'issue_url', issues have 'repository_url'
const rawIssues = [];
const rawComments = [];
for (const item of items) {
  const d = item.json;
  if (d.issue_url) {
    rawComments.push(d);
  } else if (d.repository_url || d.number !== undefined) {
    rawIssues.push(d);
  }
}

// 2. Build a set of "owner/repo/issueNumber" keys that have recent comments
const commentedIssueKeys = new Set();
for (const comment of rawComments) {
  const m = (comment.issue_url || '').match(/repos\/([^\/]+)\/([^\/]+)\/issues\/(\d+)$/);
  if (m) commentedIssueKeys.add(m[1] + '/' + m[2] + '/' + m[3]);
}

// 3. Normalize issues — skip those that only got bumped by a comment
const allEvents = [];
for (const issue of rawIssues) {
  const repoUrl = issue.repository_url || '';
  const rm = repoUrl.match(/repos\/([^\/]+)\/([^\/]+)$/);
  const owner = rm ? rm[1] : 'unknown';
  const repo = rm ? rm[2] : 'unknown';
  const key = owner + '/' + repo + '/' + issue.number;

  // If this issue has a recent comment, skip the issue event
  if (commentedIssueKeys.has(key)) continue;

  const isPR = !!issue.pull_request;
  const epoch = new Date(issue.updated_at || Date.now()).getTime();
  allEvents.push({
    json: {
      event_id: (isPR ? 'evt_github_pr_' : 'evt_github_issue_')
        + owner + '_' + repo + '_' + issue.number + '_' + epoch,
      timestamp: issue.updated_at || new Date().toISOString(),
      source: {
        platform: 'github',
        connection_id: $workflow.id,
        raw_event_type: isPR
          ? (issue.state === 'closed' ? 'pull_request_closed' : 'pull_request_updated')
          : (issue.state === 'closed' ? 'issue_closed' : 'issue_updated')
      },
      actor: {
        name: (issue.user && issue.user.login) || 'unknown',
        email: '',
        platform_handle: (issue.user && issue.user.login) || ''
      },
      subject: {
        type: isPR ? 'pull_request' : 'ticket',
        id: String(issue.number),
        title: issue.title || '',
        url: issue.html_url || ''
      },
      content: {
        body: issue.body || '',
        attachments: [],
        metadata: {
          state: issue.state,
          labels: (issue.labels || []).map(function(l) { return l.name; }),
          repo: owner + '/' + repo,
          is_pr: isPR,
          participants: [
            { role: 'author', name: (issue.user && issue.user.login) || '', handle: (issue.user && issue.user.login) || '' },
            ...(issue.assignees || []).map(function(a) { return { role: 'assignee', name: a.login || '', handle: a.login || '' }; })
          ]
        }
      }
    }
  });
}

// 4. Normalize comments — always emitted
for (const comment of rawComments) {
  if (!comment.id) continue;
  const m = (comment.issue_url || '').match(/repos\/([^\/]+)\/([^\/]+)\/issues\/(\d+)$/);
  if (!m) continue;
  const owner = m[1];
  const repo = m[2];
  const issueNumber = m[3];
  const htmlUrl = comment.html_url || '';
  const issueHtmlUrl = htmlUrl.replace(/#issuecomment-.*$/, '');
  const epoch = new Date(comment.created_at || Date.now()).getTime();

  allEvents.push({
    json: {
      event_id: 'evt_github_comment_' + owner + '_' + repo + '_' + comment.id + '_' + epoch,
      timestamp: comment.created_at || new Date().toISOString(),
      source: {
        platform: 'github',
        connection_id: $workflow.id,
        raw_event_type: 'issue_comment_created'
      },
      actor: {
        name: (comment.user && comment.user.login) || 'unknown',
        email: '',
        platform_handle: (comment.user && comment.user.login) || ''
      },
      subject: {
        type: 'ticket',
        id: issueNumber,
        title: 'Issue #' + issueNumber,
        url: issueHtmlUrl
      },
      content: {
        body: comment.body || '',
        attachments: [],
        metadata: {
          repo: owner + '/' + repo,
          issue_number: parseInt(issueNumber, 10),
          comment_id: comment.id,
          comment_url: htmlUrl,
          is_comment: true,
          participants: [
            { role: 'commenter', name: (comment.user && comment.user.login) || '', handle: (comment.user && comment.user.login) || '' }
          ]
        }
      }
    }
  });
}

return allEvents;
